from crewai import Agent, Task
from vex_sdk import VexClient

vex = VexClient(api_key='your-vex-key')

def vex_approval_gate(action: dict):
    if 'critical' in action.get('impact', ''):
        approval = vex.request_human_approval(
            summary=f"Proposed action: {action['command']}",
            evidence=action['rationale']
        )
        if not approval['approved']:
            return {'status': 'blocked', 'reason': 'Human approval denied'}
    return action

responder = Agent(
    role='Incident Responder',
    goal='Execute remediation',
    action_callback=vex_approval_gate
)

crew = Crew(agents=[responder])
